table.prettytable{margin:1em 1em 1em 0;background:#f9f9f9;border:1px #aaa solid;border-collapse:collapse}.prettytable th,.prettytable td{border:1px #aaa solid;padding:0.2em}.prettytable th{background:#f2f2f2;text-align:center}.prettytable caption{font-weight:bold}.infobox{border:1px solid #aaa;background-color:#f9f9f9;color:black;margin:0.5em 0 0.5em 1em;padding:0.2em;float:right;clear:right}.infobox td,.infobox th{vertical-align:top}.infobox caption{font-size:larger}.infobox.bordered{border-collapse:collapse}.infobox.bordered td,.infobox.bordered th{border:1px solid #aaa}.infobox.bordered .borderless td,.infobox.bordered .borderless th{border:0}.infobox.sisterproject{width:20em;font-size:90%}.infobox.standard-talk{border:1px solid #c0c090;background-color:#f8eaba}.infobox.standard-talk.bordered td,.infobox.standard-talk.bordered th{border:1px solid #c0c090}.infobox.bordered .mergedtoprow td,.infobox.bordered .mergedtoprow th{border:0;border-top:1px solid #aaa;border-right:1px solid #aaa}.infobox.bordered .mergedrow td,.infobox.bordered .mergedrow th{border:0;border-right:1px solid #aaa}.navigation-menu{overflow:hidden;background-color:#2e6f40;font-family:Arial;border-radius:10px}.navigation-menu a{float:left;font-size:16px;color:white;text-align:center;padding:14px 16px;text-decoration:none}.navigation-dropdown{float:left;overflow:hidden}.navigation-dropdown .dropdown-button{font-size:16px;border:none;outline:none;color:white;padding:14px 16px;background-color:inherit;font-family:inherit;margin:0}.dropdown-content{display:none;position:absolute;background-color:#2e6f40;min-width:160px;box-shadow:0px 8px 16px 0px rgba(0,0,0,0.2);z-index:1}.dropdown-button a{float:none}.dropdown-content a{float:none;color:white;padding:12px 16px;text-decoration:none;display:block;text-align:left}.navigation-dropdown:hover .dropdown-content{display:block}